var b="url",c="出库任务_1.html",d="generationDate",e=new Date(1781592933653.79),f="defaultAdaptiveView",g="name",h="",i="size",j="width",k=0,l="height",m="adaptiveViews",n="sketchKeys",o="s0",p="variables",q="OnLoadVariable",r="page",s="packageId",t="2b92a8da0e114abfa6f546f4af8288f7",u="type",v="Axure:Page",w="出库任务",x="notes",y="annotations",z="fn",A="1",B="ownerId",C="213dbcd6e5ce4b42bbb37750d0ce45ba",D="label",E="(文本框)",F="说明",G="<p><span>1.提示字：</span><span style=\"color:#333333;\">生产单/款号/物料/用料单位</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.支持对“关联生产”、“工作号”、“关联款号”、“用料单位”、[出库执行进度]内'物料编码'、'物料名称'的模糊查询</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.右侧含&quot;×&quot;的快捷清除按钮</span></p><p><span>2.点击【搜索】后返回查询结果</span></p>",H="2",I="166e25225d2349cc8302360bd85ed840",J="(下拉列表)",K="<p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#02A7F0;\">下拉选项</span></p><p><span>1.未选中提示字：状态</span></p><p><span>2.可选性</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.进行中</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.已关闭</span></p><p><span>3.右侧含“×‘的快捷清空按钮</span></p><p><span>4.选中或清空后</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.将对应选中项值返回当前下拉域</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.立即针对“状态”列返回筛选结果</span></p>",L="3",M="2d651e1115e94d52bb09021e13372bc1",N="<p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#02A7F0;\">下拉选项</span></p><p><span>1.未选中提示字：类型</span></p><p><span>2.可选性</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.生产</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.直接申请</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; c.自定义</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; d.</span><span style=\"color:#7F7F7F;\">其它可选项待规划…</span></p><p><span>3.右侧含“×‘的快捷清空按钮</span></p><p><span>4.选中或清空后</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.将对应选中项值返回当前下拉域</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.立即针对“类型”列返回筛选结果</span></p>",O="4",P="b00609362a9b48f8b0052cb8a3e95e07",Q="状态",R="<p><span>1.字段值</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; a.进行中：各来源创建时均初始化为'进行中'</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; b.已关闭：由当前页面进行手动关闭</span></p><p><span>2.颜色标识</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; a.进行中：绿色</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; b.已关闭：灰色</span></p>",S="5",T="288f0e7d004a4a21864c5e73fa04ccc8",U="<p><span>创建时生成出库任务单号</span></p><p><span>编码规则：FLCK+4位年月+3位流水</span></p>",V="6",W="e0ee97e955fc4051a657cdaad24cad61",X="类型",Y="<p><span>创建时固定赋值</span></p><p><span>1.直接申请：由当前页面【新建】</span></p><p><span>2.自定义：由PDA中[辅料仓库&gt;&gt;快速出库]时自动生成</span></p><p><span>3.生产：由生产领料发起，</span><span style=\"color:#0000FF;\">@马健</span><span>需求中进行首次描述</span></p><p><span style=\"color:#D9001B;\">4.其它类型暂不开发</span></p>",Z="7",ba="b1af4cdf0a4b479188c6d4dca524afb7",bb="出库进度",bc="<p><span>1.取值：用'/'分割两个数值</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; a.完成行数(左侧)：</span><span style=\"text-decoration:underline ;\">要求出库清单</span><span>下'待出库数≤0'的数据行数</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; b.全部行数(右侧)：</span><span style=\"text-decoration:underline ;\">要求出库清单</span><span>下总数据行数</span></p><p><span>2.颜色标识：跟随'状态'及'出库进度'数值</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; a.状态==已关闭：黑色</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; b.状态==进行中</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; b1.'出库进度' = 1：黑色</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; b2.'出库进度'＜1：</span><span style=\"color:#D9001B;\">红色</span></p>",bd="8",be="95bc1a1923704f06b953e4a01c250728",bf="操作",bg="<p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#02A7F0;\">关闭</span></p><p><span>1.启/禁：跟随'状态'</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; a.状态==进行中：启用(蓝色)</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; b.状态==已关闭：禁用(灰色)</span></p><p><span>2.交互：点击后直接将当前行对应的出库任务状态变更为'已关闭'</span></p><p><span><br></span></p><p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#4B7902;\">打印</span></p><p><span>暂不开发</span></p>",bh="9",bi="bddba0265fe040839cf5cc6b541c48a1",bj="出库执行进度",bk="<p><span>1.表格展示</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; a.固定标题和合计行</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; b.无须分页，中间数据固定高度行后滑动查看全部数据</span></p><p><span>2.清单描述</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; a.数据源：选中行的</span><span style=\"text-decoration:underline ;\">出库任务(FLCK)</span><span>对应的 </span><span style=\"font-family:'Nunito Sans Oblique', 'Nunito Sans', sans-serif;font-style:oblique;text-decoration:underline ;\">要求出库清单</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; b.物料编码、物料名称、颜色、规格、单位、要求数量： </span><span style=\"font-family:'Nunito Sans Oblique', 'Nunito Sans', sans-serif;font-style:oblique;text-decoration:underline ;\">要求出库清单</span><span> 下各行对应的同名字段</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; c.已出库数：</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#D9001B;\">合计</span><span>当前</span><span style=\"text-decoration:underline ;\">出库任务(FLCK)</span><span>中各</span><span style=\"text-decoration:underline ;\">要求出库行</span><span>对应于[辅料仓库系统&gt;&gt;出库日志]下</span><span style=\"text-decoration:underline ;color:#D9001B;\">明细日志</span><span style=\"color:#D9001B;\">中'出库数量'</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; d.待出库数量</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; d1.取值：</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;\">待出库数量=要求数量-已出库数</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; d2.颜色标识：跟随结果值</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; d2_1.结果值＞0：蓝色</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; d2_2.结果值 ≤ 0：黑色</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; d3.</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#D9001B;\">合计值</span><span>：仅合计&quot;待出库数量＞0&quot;的行的数值</span></p>",bl="10",bm="df097d8fe4934f1aad2a0e987b3ee25a",bn="出库明细",bo="<p><span>展示</span><span style=\"text-decoration:underline ;\">出库执行进度</span><span>内选中行对应于[辅料仓库系统&gt;&gt;出库日志]下</span><span style=\"text-decoration:underline ;color:#D9001B;\">明细日志</span><span>的关联数据</span></p><p><span><br></span></p><p><span>1.数据源匹配逻辑如下</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; a.[明细日志]中的&quot;关联出库任务&quot;与当前</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#F59A23;\">选中的出库任务的&quot;出库任务&quot;</span><span>一致</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; b.[明细日志]中的&quot;SKU&quot;与当前</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#4B7902;\">选中的执行进度行的”SKU“</span><span>一致</span></p><p><span>2.字段值描述</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; a.物料二维码：取[明细日志]中的'二维码'</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; b.数量：取[明细日志]中的'出库数量'</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; c.出库时间：取[明细日志]中的'操作时间'</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; d.关联日志：取[明细日志]中的'关联出库单'</span></p>",bp="style",bq="baseStyle",br="627587b6038d43cca051c114ac41ad32",bs="pageAlignment",bt="center",bu="fill",bv="fillType",bw="solid",bx="color",by=0xFFFFFFFF,bz="image",bA="imageAlignment",bB="near",bC="imageRepeat",bD="auto",bE="favicon",bF="sketchFactor",bG="0",bH="colorStyle",bI="appliedColor",bJ="fontName",bK="Applied Font",bL="borderWidth",bM="borderVisibility",bN="borderFill",bO=0xFF797979,bP="cornerRadius",bQ="cornerVisibility",bR="outerShadow",bS="on",bT=false,bU="offsetX",bV=5,bW="offsetY",bX="blurRadius",bY="spread",bZ="r",ca=0,cb="g",cc="b",cd="a",ce=0.349019607843137,cf="adaptiveStyles",cg="interactionMap",ch="diagram",ci="objects",cj="id",ck="449388dc5c584b039c10d358a2d35f1b",cl="friendlyType",cm="标题-1420",cn="referenceDiagramObject",co="styleType"